import{_ as a,o as e,c as n,a0 as s}from"./chunks/framework.CED9SG98.js";const h=JSON.parse('{"title":"AI 记忆运行时 (AI Memory Runtime)","description":"长期运行的 AI agent 的记忆子系统：何时读、何时写、何时审核、何时冻结；保证系统不漂移、可审计、可回滚","frontmatter":{"type":"Concept","title":"AI 记忆运行时 (AI Memory Runtime)","description":"长期运行的 AI agent 的记忆子系统：何时读、何时写、何时审核、何时冻结；保证系统不漂移、可审计、可回滚","source_url":"https://mp.weixin.qq.com/s/DJtp4QUJtJHCnNU9yarsww","source_title":"吹了几年的 AI 个人知识库，为什么还是那么难用？","source_platform":"微信公众号 (Datawhale)","ingest_date":"2026-07-13T00:00:00.000Z","access_date":"2026-07-13T00:00:00.000Z","tags":["AI记忆","运行时","Hermes","OpenClaw","知识管理","主张","权限分离"],"status":"compiled","review_count":0,"last_review":"2026-07-13T00:00:00.000Z","next_review":"2026-08-12T00:00:00.000Z"},"headers":[],"relativePath":"wiki/concepts/AI-Memory-Runtime.md","filePath":"wiki/concepts/AI-Memory-Runtime.md"}'),o={name:"wiki/concepts/AI-Memory-Runtime.md"};function i(l,t,r,p,d,c){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="ai-记忆运行时-ai-memory-runtime" tabindex="-1">AI 记忆运行时 (AI Memory Runtime) <a class="header-anchor" href="#ai-记忆运行时-ai-memory-runtime" aria-label="Permalink to &quot;AI 记忆运行时 (AI Memory Runtime)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>AI 记忆运行时是<strong>长期运行 agent 的记忆子系统</strong>：负责&quot;记忆什么时候进来、什么时候出去、谁来管、坏了能不能追&quot;。它不是&quot;agent 顺手用的功能&quot;，而是 agent 的基础设施。</p><blockquote><p>与文档知识库（RAG / Obsidian）的本质区别：RAG 是<strong>检索系统</strong>，运行时是<strong>状态维护系统</strong>——它维护一份&quot;长期知识状态&quot;，让今天得出的判断明天能自动继承。</p></blockquote><h2 id="三层架构" tabindex="-1">三层架构 <a class="header-anchor" href="#三层架构" aria-label="Permalink to &quot;三层架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│  权限层（保证系统不会乱动手）             │</span></span>
<span class="line"><span>│  ─ 事实写入权 / 约束写入权 / 工具执行权   │</span></span>
<span class="line"><span>├─────────────────────────────────────────┤</span></span>
<span class="line"><span>│  知识层（保证事实有证据）                 │</span></span>
<span class="line"><span>│  ─ 主张（Claim）为基本单位                │</span></span>
<span class="line"><span>│  ─ 绑定证据、时间、置信度、状态           │</span></span>
<span class="line"><span>├─────────────────────────────────────────┤</span></span>
<span class="line"><span>│  运行时层（保证系统不漂移）               │</span></span>
<span class="line"><span>│  ─ 冻结视图 / 异步管线 / 审计追踪        │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre></div><h2 id="关键机制" tabindex="-1">关键机制 <a class="header-anchor" href="#关键机制" aria-label="Permalink to &quot;关键机制&quot;">​</a></h2><h3 id="_1-冻结视图-session-snapshot" tabindex="-1">1. 冻结视图（Session Snapshot） <a class="header-anchor" href="#_1-冻结视图-session-snapshot" aria-label="Permalink to &quot;1. 冻结视图（Session Snapshot）&quot;">​</a></h3><p>会话开始时，把当前记忆状态冻结成一份<strong>只读视图</strong>给当前会话用。中途即使有新写入或审核通过的内容落盘，也不会修改当前会话已经看到的那份 prompt。</p><blockquote><p><strong>作用</strong>：保证同一场对话里的记忆稳定——不会说着说着变掉。</p></blockquote><h3 id="_2-异步管线-async-pipeline" tabindex="-1">2. 异步管线（Async Pipeline） <a class="header-anchor" href="#_2-异步管线-async-pipeline" aria-label="Permalink to &quot;2. 异步管线（Async Pipeline）&quot;">​</a></h3><p>不是&quot;主 agent 在 turn 里现查现写&quot;，而是这一轮结束后：</p><ol><li>后台线程做 sync（落盘新内容）</li><li>做 prefetch（把下一轮可能需要的记忆提前准备好）</li></ol><blockquote><p><strong>作用</strong>：降低主 agent 的认知负担，避免在 prompt 组装时临时拼装历史。</p></blockquote><h3 id="_3-主张作为知识单位-claim-based-knowledge" tabindex="-1">3. 主张作为知识单位（Claim-based Knowledge） <a class="header-anchor" href="#_3-主张作为知识单位-claim-based-knowledge" aria-label="Permalink to &quot;3. 主张作为知识单位（Claim-based Knowledge）&quot;">​</a></h3><p>长期知识的基本单位不是文件/段落/Markdown 页面，而是<strong>主张</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  subject: &quot;项目A&quot;,</span></span>
<span class="line"><span>  predicate: &quot;uses&quot;,</span></span>
<span class="line"><span>  object: &quot;事件驱动架构&quot;,</span></span>
<span class="line"><span>  qualifiers: { &quot;since&quot;: &quot;2024-03&quot; },</span></span>
<span class="line"><span>  evidence: [doc_ref_1, doc_ref_2],</span></span>
<span class="line"><span>  confidence: 0.85,</span></span>
<span class="line"><span>  status: &quot;active&quot; | &quot;pending_review&quot; | &quot;deprecated&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>为什么不用段落</strong>：段落很难被精确反驳，主张可以。</p><h3 id="_4-四权分离" tabindex="-1">4. 四权分离 <a class="header-anchor" href="#_4-四权分离" aria-label="Permalink to &quot;4. 四权分离&quot;">​</a></h3><table tabindex="0"><thead><tr><th>权力</th><th>谁持有</th><th>边界</th></tr></thead><tbody><tr><td><strong>事实写入权</strong></td><td>系统（自动接受低风险）/ 人工（中高风险）</td><td>模型只能提议，不能直接写成长期事实</td></tr><tr><td><strong>约束写入权</strong></td><td>人工</td><td>&quot;不要自动删邮件&quot;&quot;没确认前不要执行&quot;必须结构化存储，不可被压缩覆盖</td></tr><tr><td><strong>工具执行权</strong></td><td>人工</td><td>删邮件/发消息/转账/改生产代码不因模型&quot;觉得应该做&quot;而执行</td></tr><tr><td><strong>回顾撤销权</strong></td><td>人工</td><td>人可以推翻任何系统决策</td></tr></tbody></table><blockquote><p><strong>核心原则</strong>：危险动作不走记忆链路，单独走权限审批。</p></blockquote><h2 id="评估指标" tabindex="-1">评估指标 <a class="header-anchor" href="#评估指标" aria-label="Permalink to &quot;评估指标&quot;">​</a></h2><p>判断一套 AI 记忆系统有没有真的变好，看五个指标：</p><ol><li><strong>可追溯性</strong>：长期主张中有多少能追到原始资料的具体段落？</li><li><strong>冲突发现</strong>：新资料和旧主张冲突时，系统能不能发现？</li><li><strong>过期降权</strong>：过期主张能不能被降权或失效？</li><li><strong>对话稳定性</strong>：同一场对话里的记忆是否稳定（会不会说着说着变掉）？</li><li><strong>审核负担</strong>：每一百条候选主张要人工审几条？</li></ol><blockquote><p>如果每一百条候选主张要人工审九十条，用户迟早会放弃。</p></blockquote><h2 id="与现有-ai-系统的关系" tabindex="-1">与现有 AI 系统的关系 <a class="header-anchor" href="#与现有-ai-系统的关系" aria-label="Permalink to &quot;与现有 AI 系统的关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系统</th><th>层级</th><th>缺失</th></tr></thead><tbody><tr><td>RAG / Obsidian</td><td>文档知识库</td><td>没有运行时</td></tr><tr><td>OpenClaw（早期模式）</td><td>模型自我沉淀</td><td>模型既提议又决定真相，危险</td></tr><tr><td><strong>Hermes</strong></td><td>真正运行时</td><td>已实现冻结视图 + 异步管线</td></tr><tr><td>Karpathy LLM Wiki</td><td>文档综合</td><td>证据容易变软，没有权限层</td></tr></tbody></table><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><blockquote><p><strong>&quot;模型可以提议，但谁来负责事实？&quot;</strong></p></blockquote><p>这是 AI 记忆系统设计的核心问题。三层架构、四权分离、五个指标，都是这个问题在不同维度的展开。</p><h2 id="关联" tabindex="-1">关联 <a class="header-anchor" href="#关联" aria-label="Permalink to &quot;关联&quot;">​</a></h2><ul><li>[[PKMS]] — PKMS 的多轨制 + 增量编译是运行时层的具体实现</li><li>[[DIKW]] — 知识内化金字塔，运行时维护的对象是&quot;知识&quot;和&quot;智慧&quot;层，不是&quot;数据&quot;层</li><li>[[sources/2026-07-13-datawhale-karpathy-knowledge-base-runtime]] — 本概念的主要来源</li><li>[[sources/2026-07-12-karpathy-zhishiku-huiche]] — Andrew 从用户认知角度谈同一议题（互补）</li><li>[[entities/Hermes]] — 唯一真正实现&quot;运行时层&quot;的现有系统</li><li>[[entities/OpenClaw]] — 第二类方案（自我沉淀）的代表</li><li>[[entities/Karpathy]] — LLM Wiki 方案的提出者，本文指出其证据软肋</li></ul><h1 id="citations" tabindex="-1">Citations <a class="header-anchor" href="#citations" aria-label="Permalink to &quot;Citations&quot;">​</a></h1><ul><li>来源: Datawhale 公众号《吹了几年的 AI 个人知识库，为什么还是那么难用？》(2026-04-27)</li><li>抓取工具: weixin-article-reader v1.1.0（保留图片 + 嵌套 div 精准截断）</li></ul>`,34)])])}const q=a(o,[["render",i]]);export{h as __pageData,q as default};
